#include <bits/stdc++.h>
using namespace std;
const int N=1005;
int n,m,q,dis[N];
vector<int> g[N];
bitset<N> bs[N][N];
void bfs(int u)
{
	queue<int> q;
	memset(dis,0x3f,sizeof(dis));
	q.push(u);
	dis[u]=0;
	while(!q.empty())
	{
		int tmp=q.front();
		q.pop();
		for(int i=0;i<g[tmp].size();i++)
		{
			int v=g[tmp][i];
			if(dis[v]>dis[tmp]+1)
			{
				dis[v]=dis[tmp]+1;
				q.push(v);
			}
		}
	}
}
int main()
{
    ios::sync_with_stdio(0);
    cin.tie(0),cout.tie(0);
	cin>>n>>m>>q;
	while(m--)
	{
		int u,v;
		cin>>u>>v;
		g[u].push_back(v);
		g[v].push_back(u);
	}
	for(int i=1;i<=n;i++)
	{
		bfs(i);
		for(int j=1;j<=n;j++)
		{
			if(dis[j]!=0x3f3f3f3f) bs[i][dis[j]][j]=1;
		}
		for(int j=1;j<=n;j++) bs[i][j]|=bs[i][j-1];
	}
	while(q--)
	{
		bitset<N> ans;
		int num;
		cin>>num;
		while(num--)
		{
			int x,y;
			cin>>x>>y;
			ans|=bs[x][y];
		}
		cout<<ans.count()<<'\n';
	}
	return 0;
}
